import { HttpService } from '@nestjs/axios';
import { Injectable, Logger } from '@nestjs/common';

import { EnvConfigService } from '@modules/env-config/env-config.service';
import { JiraInstallationModel } from '@modules/jira/db/jira-installations.model';
import {
	IAtlassianResource,
	IAtlassianTokenResponse,
	IJiraApiBoardResponse,
	IJiraApiProject,
	IJiraApiSearchResponse,
	IJiraApiSprintResponse,
	IJiraApiWorklog,
} from '@modules/jira/types/jira-api.interface';
import { IJiraInstallationBase } from '@modules/jira/types/jira-installation.interface';

import { JIRA_CLIENT_ID, JIRA_CLIENT_SECRET, JIRA_CALLBACK_URL } from '@constants/env-variables.constant';

const TOKEN_REFRESH_BUFFER_MS = 5 * 60 * 1000;
const ATLASSIAN_TOKEN_URL = 'https://auth.atlassian.com/oauth/token';
const ATLASSIAN_RESOURCES_URL = 'https://api.atlassian.com/oauth/token/accessible-resources';

@Injectable()
export class JiraApiService {
	private readonly logger = new Logger(JiraApiService.name);

	constructor(
		private readonly httpService: HttpService,
		private readonly configService: EnvConfigService,
		private readonly installationModel: JiraInstallationModel,
	) {}

	async exchangeCode({
		code,
	}: {
		code: string;
	}): Promise<IAtlassianTokenResponse> {
		const { data } = await this.httpService.axiosRef.post<IAtlassianTokenResponse>(
			ATLASSIAN_TOKEN_URL,
			{
				grant_type: 'authorization_code',
				client_id: this.configService.get<string>({ key: JIRA_CLIENT_ID }),
				client_secret: this.configService.get<string>({ key: JIRA_CLIENT_SECRET }),
				redirect_uri: this.configService.get<string>({ key: JIRA_CALLBACK_URL }),
				code,
			},
		);
		return data;
	}

	async getAccessibleResources({
		accessToken,
	}: {
		accessToken: string;
	}): Promise<IAtlassianResource[]> {
		const { data } = await this.httpService.axiosRef.get<IAtlassianResource[]>(
			ATLASSIAN_RESOURCES_URL,
			{ headers: { Authorization: `Bearer ${accessToken}` } },
		);
		return data;
	}

	async getValidToken({
		installation,
	}: {
		installation: IJiraInstallationBase;
	}): Promise<string> {
		const expiresAt = new Date(installation.token_expires_at).getTime();
		const now = Date.now();

		if (expiresAt - now > TOKEN_REFRESH_BUFFER_MS) {
			return installation.access_token;
		}

		try {
			const refreshed = await this.refreshToken({
				refreshToken: installation.refresh_token,
			});

			const tokenExpiresAt = new Date(Date.now() + refreshed.expires_in * 1000);

			await this.installationModel.updateTokens({
				id: installation._id,
				accessToken: refreshed.access_token,
				refreshToken: refreshed.refresh_token,
				tokenExpiresAt,
			});

			this.logger.debug(`Refreshed token for installation ${installation._id}`);
			return refreshed.access_token;
		} catch (error) {
			await this.installationModel.markNeedsReauth({ id: installation._id });
			this.logger.error(
				`Token refresh failed for installation ${installation._id}: ${(error as Error).message}`,
			);
			throw error;
		}
	}

	async listProjects({
		cloudId,
		token,
	}: {
		cloudId: string;
		token: string;
	}): Promise<IJiraApiProject[]> {
		const base = this.apiBase({ cloudId });
		const projects: IJiraApiProject[] = [];
		let startAt = 0;
		const maxResults = 50;

		while (true) {
			const { data } = await this.httpService.axiosRef.get<{
				values: IJiraApiProject[];
				isLast: boolean;
			}>(`${base}/project/search`, {
				headers: { Authorization: `Bearer ${token}` },
				params: { startAt, maxResults, typeKey: 'software' },
			});

			projects.push(...data.values);
			if (data.isLast || data.values.length === 0) break;
			startAt += maxResults;
		}

		return projects;
	}

	async searchIssues({
		cloudId,
		token,
		jql,
		startAt,
	}: {
		cloudId: string;
		token: string;
		jql: string;
		startAt: number;
	}): Promise<IJiraApiSearchResponse> {
		const base = this.apiBase({ cloudId });
		const { data } = await this.httpService.axiosRef.post<IJiraApiSearchResponse>(
			`${base}/search/jql`,
			{
				jql,
				startAt,
				maxResults: 100,
				expand: ['changelog'],
				fields: [
					'summary', 'issuetype', 'status', 'priority',
					'assignee', 'reporter', 'customfield_10016',
					'resolutiondate', 'created', 'updated',
				],
			},
			{ headers: { Authorization: `Bearer ${token}` } },
		);
		return data;
	}

	async getWorklogsForIssue({
		cloudId,
		token,
		issueId,
	}: {
		cloudId: string;
		token: string;
		issueId: string;
	}): Promise<IJiraApiWorklog[]> {
		const base = this.apiBase({ cloudId });
		const { data } = await this.httpService.axiosRef.get<{
			worklogs: IJiraApiWorklog[];
		}>(`${base}/issue/${issueId}/worklog`, {
			headers: { Authorization: `Bearer ${token}` },
			params: { maxResults: 5000 },
		});
		return data.worklogs;
	}

	async listBoards({
		cloudId,
		token,
		projectKeyOrId,
	}: {
		cloudId: string;
		token: string;
		projectKeyOrId: string;
	}): Promise<IJiraApiBoardResponse> {
		const agileBase = this.agileBase({ cloudId });
		const { data } = await this.httpService.axiosRef.get<IJiraApiBoardResponse>(
			`${agileBase}/board`,
			{
				headers: { Authorization: `Bearer ${token}` },
				params: { projectKeyOrId, maxResults: 50 },
			},
		);
		return data;
	}

	async listSprints({
		cloudId,
		token,
		boardId,
		startAt,
	}: {
		cloudId: string;
		token: string;
		boardId: number;
		startAt: number;
	}): Promise<IJiraApiSprintResponse> {
		const agileBase = this.agileBase({ cloudId });
		const { data } = await this.httpService.axiosRef.get<IJiraApiSprintResponse>(
			`${agileBase}/board/${boardId}/sprint`,
			{
				headers: { Authorization: `Bearer ${token}` },
				params: { startAt, maxResults: 50 },
			},
		);
		return data;
	}

	private async refreshToken({
		refreshToken,
	}: {
		refreshToken: string;
	}): Promise<IAtlassianTokenResponse> {
		const { data } = await this.httpService.axiosRef.post<IAtlassianTokenResponse>(
			ATLASSIAN_TOKEN_URL,
			{
				grant_type: 'refresh_token',
				client_id: this.configService.get<string>({ key: JIRA_CLIENT_ID }),
				client_secret: this.configService.get<string>({ key: JIRA_CLIENT_SECRET }),
				refresh_token: refreshToken,
			},
		);
		return data;
	}

	private apiBase({ cloudId }: { cloudId: string }): string {
		return `https://api.atlassian.com/ex/jira/${cloudId}/rest/api/3`;
	}

	private agileBase({ cloudId }: { cloudId: string }): string {
		return `https://api.atlassian.com/ex/jira/${cloudId}/rest/agile/1.0`;
	}
}
